#include <bits/stdc++.h>
using namespace std;

int c[1000005], t[1000005], d[1000005], sd[1000005];

int main()
{
	int n, q;
	cin >> n >> q;
	for(int i = 1; i <= n; i++)
		cin >> c[i];
	for(int i = 1; i <= n; i++)
		cin >> t[i];
	for(int i = 1; i <= n; i++)
		d[max(c[i] - t[i] - 1, 0)]++;
	for(int i = 1000000; i >= 1; i--)
		sd[i] = sd[i + 1] + d[i];
	for(int i = 1; i <= q; i++)
	{
		int s, v;
		cin >> v >> s;
		if(sd[s] >= v) cout << "YES" << endl;
		else cout << "NO" << endl;
	}
}
